// Import of required libraries
import { test } from '@playwright/test';
import { expect, newSkyrampPlaywrightPage } from '@skyramp/skyramp';

const pageTimeout = 15000;

test('testUi', async ({ page }) => {
    test.setTimeout(145000);

    const errors: Error[] = [];
    page.on('pageerror', (err) => errors.push(err));

    // set default timeout for all locator/page actions in this test
    page.setDefaultTimeout(pageTimeout);
    // Wrap playwright page with Skyramp page
    page = newSkyrampPlaywrightPage(page);

    await page.goto("http://localhost:8055/admin/login");
    await page.getByRole("textbox", { name: "Email" }).fill("admin@example.com");
    await page.getByRole("textbox", { name: "Password" }).fill("admin");
    await page.getByRole("button", { name: "Sign In" }).click();
    await page.goto("http://localhost:8055/admin/content/+wizard");
    await page.waitForLoadState('networkidle');
    await page.locator('[data-test="wizard-name-input"]').waitFor({ state: 'visible', timeout: 10000 });

    await page.locator('[data-test="wizard-name-input"]').fill('my_blog_posts');
    await page.getByRole("button", { name: "Next" }).click();

    await page.locator('[data-test="wizard-fields-name-0"]').fill('title');
    await page.getByRole("button", { name: "+ Add field" }).click();
    await expect(page.locator('[data-test="wizard-fields-name-0"]')).toHaveValue('title');
    await expect(page.locator('[data-test="wizard-fields-rows"]').getByRole('textbox')).toHaveCount(2);

    await page.locator('[data-test="wizard-fields-name-1"]').fill('body');
    await page.locator('[data-test="wizard-fields-type-1"]').selectOption('text');
    await expect(page.locator('[data-test="wizard-fields-name-1"]')).toHaveValue('body');

    await page.getByRole("button", { name: "Next" }).click();
    await page.getByRole("button", { name: "Next" }).click();
    await page.getByRole("button", { name: "Next" }).click();

    await expect(page.locator('[data-test="review-summary-name"]')).toContainText("my_blog_posts");
    await expect(page.locator('[data-test="review-summary-fields"]')).toContainText("2 fields");
    await expect(page.locator('[data-test="review-summary-fields"]')).toContainText("title");
    await expect(page.locator('[data-test="review-summary-fields"]')).toContainText("body");
    await expect(page.locator('[data-test="review-summary-permissions"]')).toContainText("4 permission grants");

    expect(errors).toHaveLength(0);
});
